from flask import Flask, session, request, jsonify
import redis
import functools
import time
import json

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# Connect to Redis
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0, decode_responses=True)

@app.before_request
def check_session():
    if 'user_id' not in session:
        session['user_id'] = None

@app.route('/login', methods=['POST'])
def login():
    user_id = request.json.get('user_id')
    if user_id:
        session['user_id'] = user_id
        # Store session in Redis
        redis_client.setex(f"session:{session.sid}", 3600, json.dumps(dict(session)))
        return jsonify({"status": "logged_in"})
    return jsonify({"status": "failed"}), 401

@app.route('/logout', methods=['POST'])
def logout():
    session.clear()
    # Remove session from Redis
    redis_client.delete(f"session:{request.sid}")
    return jsonify({"status": "logged_out"})

def cache(expiration=300):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Create cache key
            cache_key = f"cache:{func.__name__}:{hash(str(args) + str(kwargs))}"
            
            # Try to get from cache
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return json.loads(cached_result)
            
            # Execute function and cache result
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, expiration, json.dumps(result))
            return result
        return wrapper
    return decorator

@app.route('/user/<int:user_id>')
@cache(expiration=600)
def get_user(user_id):
    # Simulate expensive database query
    time.sleep(1)
    return {"user_id": user_id, "name": f"User {user_id}", "email": f"user{user_id}@example.com"}

@app.route('/data/<path:resource>')
@cache(expiration=1800)
def get_data(resource):
    # Simulate expensive database query
    time.sleep(2)
    return {"resource": resource, "data": f"expensive_data_for_{resource}"}

